export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: any[];
};

export type ScenarioResult = {
  results: any[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const quote = (step: any) => {
  if (step.items.length === 0) return { premium: PROCESSING_FEE };
  const itemTotal = step.items.reduce((sum: number, item: any) => {
    const base = BASE_PREMIUM[item.type];
    return sum + base * (1 + FIRST_INSURANCE_SURCHARGE);
  }, 0);
  return { premium: itemTotal + PROCESSING_FEE };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") return quote(step);
    return {};
  });
  return { results };
};

