export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: any[];
};

export type ScenarioResult = {
  results: any[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const COMPONENT_TYPES = new Set(["rune"]);

const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);

const componentBasePremium = (count: number, perUnit: number) => {
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
  return count * perUnit;
};

const itemBases = (items: any[]): number[] => {
  const bases: number[] = [];
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      bases.push(BASE_PREMIUM[item.type]);
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    bases.push(componentBasePremium(count, BASE_PREMIUM[type]));
  }
  return bases;
};

const quote = (step: any) => {
  const bases = itemBases(step.items);
  const total = bases.reduce(
    (sum, base) => sum + base * (1 + FIRST_INSURANCE_SURCHARGE),
    PROCESSING_FEE,
  );
  return { premium: roundUp(total) };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") return quote(step);
    return {};
  });
  return { results };
};

