import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Base premium calculation - simplest cases
  it("empty item list yields premium of only the 5 G processing fee", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("quote for a single plain sword for a newcomer yields 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("quote for a single plain amulet for a newcomer yields 71 G (60 + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("quote for a single plain staff for a newcomer yields 93 G (80 + 8 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("quote for a single plain potion for a newcomer yields 49 G (40 + 4 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });
  it("quote for a single rune component for a newcomer yields 33 G (25 + 2.5 first-ins + 5 fee, rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });

  // Multiple items
  it("quote for two plain swords for a newcomer yields 225 G (2*(100+10) + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }, { type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 225 });
  });

  // Component block discount
  it("quote for 2 runes for a newcomer yields 60 G (2*25 + 5 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("quote for exactly 3 runes uses 60 G block base premium (60 + 6 first-ins + 5 fee = 71 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it.todo("quote for 4 runes uses 25 G each (block requires exactly 3)");
  it.todo("quote for 3 runes + 3 moonstones applies two separate blocks");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% curse surcharge to that item only");
  it.todo("highly enchanted (level >= 5) sword adds 30% surcharge");
  it.todo("cursed AND highly enchanted item stacks both surcharges");

  // Policy-wide modifiers
  it.todo("long-standing customer (>= 2 years) gets 20% loyalty discount");
  it.todo("first quote in scenario adds 10% first-insurance surcharge");
  it.todo("second quote in scenario gets 15% follow-up contract discount");

  // Rounding
  it.todo("premium rounds up (in MHPCO's favor)");

  // Newcomer integration example: cursed sword -> 165 G
  it.todo("newcomer cursed sword integration example yields 165 G");

  // Long-standing customer's second contract: 160 G
  it.todo("long-standing customer's second contract integration yields 160 G");

  // Claims - basic
  it.todo("claim with standard damage subtracts 100 G deductible");
  it.todo("claim on highly enchanted (>= 8) item reimburses 50% then deductible");
  it.todo("claim on dragon-material item gets full reimbursement then deductible");
  it.todo("dragon material AND high enchantment - 50% rule wins, then deductible");
  it.todo("multiple damage entries each get their own deductible");
  it.todo("payout rounds down (in MHPCO's favor)");

  // Error/edge cases
  it.todo("quote with unknown item type causes error");
  it.todo("claim referencing item not in policy causes error");
  it.todo("claim with negative damage amount causes error");
  it.todo("claim with more damage entries of a type than policy covers causes error");
});

