export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: any[];
};

export type ScenarioResult = {
  results: any[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);

const componentBasePremium = (count: number, perUnit: number) => {
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
  return count * perUnit;
};

type ItemEntry = { base: number; surchargePct: number };

const itemEntries = (items: any[]): ItemEntry[] => {
  const entries: ItemEntry[] = [];
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      const base = BASE_PREMIUM[item.type];
      let surchargePct = FIRST_INSURANCE_SURCHARGE;
      if (item.cursed) surchargePct += CURSE_SURCHARGE;
      if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
        surchargePct += HIGH_ENCHANTMENT_SURCHARGE;
      }
      entries.push({ base, surchargePct });
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    entries.push({
      base: componentBasePremium(count, BASE_PREMIUM[type]),
      surchargePct: FIRST_INSURANCE_SURCHARGE,
    });
  }
  return entries;
};

const quote = (step: any) => {
  const entries = itemEntries(step.items);
  const total = entries.reduce(
    (sum, { base, surchargePct }) => sum + base * (1 + surchargePct),
    PROCESSING_FEE,
  );
  return { premium: roundUp(total) };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => {
    if (step.op === "quote") return quote(step);
    return {};
  });
  return { results };
};

