32	const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);
33	
34	const componentBasePremium = (count: number, perUnit: number) => {
35	  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
36	  return count * perUnit;
37	};
38	
39	type PremiumEntry = { base: number; surchargePct: number };
40	
41	const itemSurchargePct = (item: any): number =>
42	  FIRST_INSURANCE_SURCHARGE +
43	  (item.cursed ? CURSE_SURCHARGE : 0) +
44	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
45	    ? HIGH_ENCHANTMENT_SURCHARGE
46	    : 0);
47	
48	const singleItemEntry = (item: any): PremiumEntry => ({
49	  base: BASE_PREMIUM[item.type],
50	  surchargePct: itemSurchargePct(item),
51	});
52	
53	const componentGroupEntry = (type: string, count: number): PremiumEntry => ({
54	  base: componentBasePremium(count, BASE_PREMIUM[type]),
55	  surchargePct: FIRST_INSURANCE_SURCHARGE,
56	});
57	
58	const premiumEntries = (items: any[]): PremiumEntry[] => {
59	  const singles = items
60	    .filter((item) => !COMPONENT_TYPES.has(item.type))
61	    .map(singleItemEntry);
62	  const componentCounts = items
63	    .filter((item) => COMPONENT_TYPES.has(item.type))
64	    .reduce<Record<string, number>>(
65	      (counts, item) => ({ ...counts, [item.type]: (counts[item.type] ?? 0) + 1 }),
66	      {},
67	    );
68	  const componentGroups = Object.entries(componentCounts).map(
69	    ([type, count]) => componentGroupEntry(type, count),
70	  );
71	  return [...singles, ...componentGroups];
72	};
73	
74	const policyModifierPct = (
75	  customer: Scenario["customer"],
76	  isFollowUp: boolean,
77	): number => {
78	  const loyalty =
79	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0;
80	  const followUp = isFollowUp ? FOLLOWUP_DISCOUNT : 0;
81	  return -(loyalty + followUp);
82	};
83	
84	const quote = (
85	  step: any,
86	  customer: Scenario["customer"],
87	  isFollowUp: boolean,
88	) => {
89	  const policyPct = policyModifierPct(customer, isFollowUp);
90	  const total = premiumEntries(step.items).reduce(
91	    (sum, { base, surchargePct }) => sum + base * (1 + surchargePct + policyPct),
92	    PROCESSING_FEE,
93	  );
94	  return { premium: roundUp(total) };
95	};
96	
97	const previousQuoteCount = (steps: any[], index: number): number =>
98	  steps.slice(0, index).filter((step) => step.op === "quote").length;
99	
100	export const runScenario = (scenario: Scenario): ScenarioResult => {
101	  const results = scenario.steps.map((step, index) => {
102	    if (step.op === "quote") {
103	      const isFollowUp = previousQuoteCount(scenario.steps, index) > 0;
104	      return quote(step, scenario.customer, isFollowUp);
105	    }
106	    return {};
107	  });
108	  return { results };
109	};

