import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Base premium calculation - simplest cases
  it("empty item list yields premium of only the 5 G processing fee", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });
  it("quote for a single plain sword for a newcomer yields 115 G (100 base + 10 first-insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("quote for a single plain amulet for a newcomer yields 71 G (60 + 6 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("quote for a single plain staff for a newcomer yields 93 G (80 + 8 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 93 });
  });
  it("quote for a single plain potion for a newcomer yields 49 G (40 + 4 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 49 });
  });
  it("quote for a single rune component for a newcomer yields 33 G (25 + 2.5 first-ins + 5 fee, rounded up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 33 });
  });

  // Multiple items
  it("quote for two plain swords for a newcomer yields 225 G (2*(100+10) + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }, { type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 225 });
  });

  // Component block discount
  it("quote for 2 runes for a newcomer yields 60 G (2*25 + 5 first-ins + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("quote for exactly 3 runes uses 60 G block base premium (60 + 6 first-ins + 5 fee = 71 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("quote for 4 runes for a newcomer yields 115 G (4*25 + 10 first-ins + 5 fee; no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" },
      ] }],
    });
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("quote for 3 runes + 3 moonstones applies two separate blocks (120 + 12 + 5 = 137 G)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "rune" }, { type: "rune" }, { type: "rune" },
        { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" },
      ] }],
    });
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Item-specific modifiers
  it("cursed sword + plain amulet (newcomer) → only sword gets curse surcharge", () => {
    // sword: 100 + 50 curse + 10 first-ins = 160
    // amulet: 60 + 6 first-ins = 66
    // total: 226 + 5 fee = 231
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [
        { type: "sword", cursed: true },
        { type: "amulet", cursed: false },
      ] }],
    });
    expect(result.results[0]).toEqual({ premium: 231 });
  });
  it("highly enchanted (level 5) sword (newcomer) adds 30% surcharge → 145 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 145 });
  });
  it("cursed AND highly enchanted (level 5) sword (newcomer) stacks both → 195 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", cursed: true, enchantment: 5 }] }],
    });
    expect(result.results[0]).toEqual({ premium: 195 });
  });

  // Policy-wide modifiers
  it("long-standing customer (2 years) with plain sword → 95 G (100 + 10 first-ins - 20 loyalty + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 2 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 95 });
  });
  it.todo("first quote in scenario adds 10% first-insurance surcharge (covered by earlier tests)");
  it("second quote in scenario gets 15% follow-up contract discount", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword" }] },
        { op: "quote", items: [{ type: "sword" }] },
      ],
    });
    // quote 1: 100 + 10 first-ins + 5 fee = 115
    // quote 2: 100 + 10 first-ins - 15 follow-up + 5 fee = 100
    expect(result.results).toEqual([{ premium: 115 }, { premium: 100 }]);
  });

  // Rounding
  it("premium rounds up - 197.5 G → 198 G per spec", () => {
    // construct: 3 swords newcomer (3*(100+10)+5 = 335, integer). need .5 result.
    // Use 1 amulet + 1 rune (newcomer): 60+6 + 25+2.5 + 5 = 98.5 → 99
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }, { type: "rune" }] }],
    });
    expect(result.results[0]).toEqual({ premium: 99 });
  });

  // Newcomer integration example: cursed sword -> 165 G
  it("newcomer cursed sword integration example yields 165 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }] }],
    });
    expect(result.results[0]).toEqual({ premium: 165 });
  });

  // Long-standing customer's second contract: 160 G
  it("long-standing customer's second contract integration yields 160 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 3 },
      steps: [
        { op: "quote", items: [{ type: "potion" }] },
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 7, cursed: true }] },
      ],
    });
    expect(result.results[1]).toEqual({ premium: 160 });
  });

  // Claims - basic
  it("claim with standard damage subtracts 100 G deductible (regular sword damage 500 → 400)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3 }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 500 }] } },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400 });
  });
  it("claim on highly enchanted (>= 8) item reimburses 50% then deductible (steel ench 9, damage 1000 → 400)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "steel", enchantment: 9 }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 1000 }] } },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 400 });
  });
  it("dragon-material sword ench 5, damage 800 G → payout 700 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "sword", material: "dragon", enchantment: 5 }] },
        { op: "claim", policy: 0, incident: { cause: "fire", damages: [{ itemType: "sword", amount: 800 }] } },
      ],
    });
    expect(result.results[1]).toEqual({ payout: 700 });
  });
  it.todo("dragon material AND high enchantment - 50% rule wins, then deductible");
  it.todo("multiple damage entries each get their own deductible");
  it.todo("payout rounds down (in MHPCO's favor)");

  // Error/edge cases
  it.todo("quote with unknown item type causes error");
  it.todo("claim referencing item not in policy causes error");
  it.todo("claim with negative damage amount causes error");
  it.todo("claim with more damage entries of a type than policy covers causes error");
});

export type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: any[];
};

export type ScenarioResult = {
  results: any[];
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const FOLLOWUP_DISCOUNT = 0.15;
const CLAIM_DEDUCTIBLE = 100;
const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const roundUp = (value: number) => Math.ceil(Math.round(value * 1e6) / 1e6);

const componentBasePremium = (count: number, perUnit: number) => {
  if (count === COMPONENT_BLOCK_SIZE) return COMPONENT_BLOCK_PREMIUM;
  return count * perUnit;
};

type PremiumEntry = { base: number; surchargePct: number };

const itemSurchargePct = (item: any): number =>
  FIRST_INSURANCE_SURCHARGE +
  (item.cursed ? CURSE_SURCHARGE : 0) +
  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
    ? HIGH_ENCHANTMENT_SURCHARGE
    : 0);

const singleItemEntry = (item: any): PremiumEntry => ({
  base: BASE_PREMIUM[item.type],
  surchargePct: itemSurchargePct(item),
});

const componentGroupEntry = (type: string, count: number): PremiumEntry => ({
  base: componentBasePremium(count, BASE_PREMIUM[type]),
  surchargePct: FIRST_INSURANCE_SURCHARGE,
});

const premiumEntries = (items: any[]): PremiumEntry[] => {
  const singles = items
    .filter((item) => !COMPONENT_TYPES.has(item.type))
    .map(singleItemEntry);
  const componentCounts = items
    .filter((item) => COMPONENT_TYPES.has(item.type))
    .reduce<Record<string, number>>(
      (counts, item) => ({ ...counts, [item.type]: (counts[item.type] ?? 0) + 1 }),
      {},
    );
  const componentGroups = Object.entries(componentCounts).map(
    ([type, count]) => componentGroupEntry(type, count),
  );
  return [...singles, ...componentGroups];
};

const policyModifierPct = (
  customer: Scenario["customer"],
  isFollowUp: boolean,
): number => {
  const loyalty =
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0;
  const followUp = isFollowUp ? FOLLOWUP_DISCOUNT : 0;
  return -(loyalty + followUp);
};

const quote = (
  step: any,
  customer: Scenario["customer"],
  isFollowUp: boolean,
) => {
  const policyPct = policyModifierPct(customer, isFollowUp);
  const total = premiumEntries(step.items).reduce(
    (sum, { base, surchargePct }) => sum + base * (1 + surchargePct + policyPct),
    PROCESSING_FEE,
  );
  return { premium: roundUp(total) };
};

const previousQuoteCount = (steps: any[], index: number): number =>
  steps.slice(0, index).filter((step) => step.op === "quote").length;

const damagePayout = (amount: number, item: any): number => {
  let reimbursed = amount;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
    reimbursed = amount * HIGH_ENCHANTMENT_PAYOUT_RATE;
  }
  return Math.max(0, reimbursed - CLAIM_DEDUCTIBLE);
};

const claim = (step: any, policyItems: any[]): { payout: number } => {
  const total = step.incident.damages.reduce((sum: number, d: any) => {
    const item = policyItems.find((it) => it.type === d.itemType);
    return sum + damagePayout(d.amount, item);
  }, 0);
  return { payout: Math.floor(total) };
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const isFollowUp = previousQuoteCount(scenario.steps, index) > 0;
      return quote(step, scenario.customer, isFollowUp);
    }
    if (step.op === "claim") {
      const policyStep = scenario.steps[step.policy];
      return claim(step, policyStep.items);
    }
    return {};
  });
  return { results };
};

